import{_ as n,o as i,c as r,ag as a}from"./chunks/framework.CvgP6Fyv.js";const d=JSON.parse('{"title":"Profil","description":"","frontmatter":{},"headers":[],"relativePath":"de/account/profile.md","filePath":"de/account/profile.md"}'),t={name:"de/account/profile.md"};function l(s,e,h,o,c,u){return i(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="profil" tabindex="-1">Profil <a class="header-anchor" href="#profil" aria-label="Permalink to &quot;Profil&quot;">​</a></h1><p>Verwalten Sie Ihre persönlichen Kontoeinstellungen, Präferenzen und Benachrichtigungen.</p><h2 id="personliche-informationen" tabindex="-1">Persönliche Informationen <a class="header-anchor" href="#personliche-informationen" aria-label="Permalink to &quot;Persönliche Informationen&quot;">​</a></h2><p>Aktualisieren Sie Ihr Profil über die <strong>Profil</strong>-Seite:</p><ul><li><strong>Name</strong> — Ihr Anzeigename</li><li><strong>E-Mail</strong> — Ihre Anmelde-E-Mail</li><li><strong>Profilbild</strong> — Laden Sie ein Foto oder einen Avatar hoch</li><li><strong>Sprache</strong> — Oberflächensprache (Englisch, Niederländisch, Deutsch, Französisch)</li></ul><h3 id="sprache-andern" tabindex="-1">Sprache ändern <a class="header-anchor" href="#sprache-andern" aria-label="Permalink to &quot;Sprache ändern&quot;">​</a></h3><ol><li>Gehen Sie zu <strong>Profil</strong></li><li>Wählen Sie Ihre bevorzugte Sprache</li><li>Die Oberfläche wird sofort aktualisiert</li></ol><p>Ihre Spracheinstellung beeinflusst:</p><ul><li>Alle UI-Texte und Navigation</li><li>Datums- und Zahlenformatierung</li><li>Standardsprache für neue Dokumente</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Die Rechnungssprache wird pro Rechnung festgelegt und kann von Ihrer Oberflächensprache abweichen. Sie können eine niederländische Rechnung versenden, während Sie die deutsche Oberfläche verwenden.</p></div><h2 id="passwort" tabindex="-1">Passwort <a class="header-anchor" href="#passwort" aria-label="Permalink to &quot;Passwort&quot;">​</a></h2><p>Passwort ändern:</p><ol><li>Gehen Sie zu <strong>Profil &gt; Passwort</strong></li><li>Geben Sie Ihr aktuelles Passwort ein</li><li>Geben Sie Ihr neues Passwort ein und bestätigen Sie es</li><li>Klicken Sie auf <strong>Speichern</strong></li></ol><p>Wenn Sie sich mit Google oder Microsoft registriert haben, können Sie trotzdem ein Passwort für die E-Mail-basierte Anmeldung festlegen.</p><h2 id="benachrichtigungseinstellungen" tabindex="-1">Benachrichtigungseinstellungen <a class="header-anchor" href="#benachrichtigungseinstellungen" aria-label="Permalink to &quot;Benachrichtigungseinstellungen&quot;">​</a></h2><p>Steuern Sie, welche Benachrichtigungen Sie erhalten und wie:</p><h3 id="e-mail-benachrichtigungen" tabindex="-1">E-Mail-Benachrichtigungen <a class="header-anchor" href="#e-mail-benachrichtigungen" aria-label="Permalink to &quot;E-Mail-Benachrichtigungen&quot;">​</a></h3><ul><li><strong>Rechnung bezahlt</strong> — Wenn ein Kunde eine Rechnung bezahlt</li><li><strong>Angebotsanfrage eingegangen</strong> — Wenn jemand über Ihre Geschäftsseite ein Angebot anfragt</li><li><strong>Teamaktivitäten</strong> — Wenn Teammitglieder Aktionen durchführen</li><li><strong>Ausgabe genehmigt</strong> — Wenn eine Ausgabe genehmigt wird</li></ul><h3 id="e-mail-zusammenfassung" tabindex="-1">E-Mail-Zusammenfassung <a class="header-anchor" href="#e-mail-zusammenfassung" aria-label="Permalink to &quot;E-Mail-Zusammenfassung&quot;">​</a></h3><p>Wählen Sie, wie häufig Sie Zusammenfassungs-E-Mails erhalten:</p><ul><li><strong>Täglich</strong> — Tägliche Aktivitätsübersicht</li><li><strong>Wöchentlich</strong> — Wöchentliche Zusammenfassung</li><li><strong>Monatlich</strong> — Monatlicher Überblick</li><li><strong>Aus</strong> — Keine Zusammenfassungs-E-Mails</li></ul><h3 id="push-benachrichtigungen" tabindex="-1">Push-Benachrichtigungen <a class="header-anchor" href="#push-benachrichtigungen" aria-label="Permalink to &quot;Push-Benachrichtigungen&quot;">​</a></h3><p>Aktivieren Sie Browser-Push-Benachrichtigungen für Echtzeit-Warnungen, wenn die App geöffnet ist.</p><h3 id="in-app-benachrichtigungen" tabindex="-1">In-App-Benachrichtigungen <a class="header-anchor" href="#in-app-benachrichtigungen" aria-label="Permalink to &quot;In-App-Benachrichtigungen&quot;">​</a></h3><p>Echtzeit-Benachrichtigungen innerhalb der MyCompanyDesk-Oberfläche. Diese sind immer aktiv und erscheinen in der Benachrichtigungsglocke in der Kopfzeile.</p><h2 id="verbundene-apps" tabindex="-1">Verbundene Apps <a class="header-anchor" href="#verbundene-apps" aria-label="Permalink to &quot;Verbundene Apps&quot;">​</a></h2><p>Sehen und verwalten Sie OAuth-Verbindungen:</p><ul><li><strong>Google</strong> — Verbunden für Anmeldung und/oder Gmail-Versand</li><li><strong>Microsoft</strong> — Verbunden für Anmeldung und/oder Outlook-Versand</li></ul><p>Widerrufen Sie den Zugriff, um eine App von Ihrem Konto zu trennen.</p>',29)])])}const p=n(t,[["render",l]]);export{d as __pageData,p as default};
